"""
Parameterized generator for GH555_flagsmith_4299.

Source PR:    https://github.com/Flagsmith/flagsmith/pull/4299
Source Issue: N/A

Seed varies: renames 'api_key' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH555_flagsmith_4299'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH555_flagsmith_4299'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('api_key', 'api_key' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH555_flagsmith_4299',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'Flagsmith/flagsmith',
                "pr_number": 4299,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/Flagsmith/flagsmith/pull/4299",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'frontend/common/providers/Permission.tsx': "import React, { FC, ReactNode } from 'react'\nimport { useGetPermissionQuery } from 'common/services/usePermission'\nimport { PermissionLevel } from 'common/types/requests'\nimport AccountStore from 'common/stores/account-store' // we need this to make JSX compile\n\ntype PermissionType = {\n  id: any\n  permission: string\n  level: PermissionLevel\n  children: (data: { permission: boolean; isLoading: boolean }) => ReactNode\n}\n\nexport const useHasPermission = ({\n  id,\n  level,\n  permission,\n}: Omit<PermissionType, 'children'>) => {\n  const { data, isLoading } = useGetPermissionQuery(\n    { id: `${id}`, level },\n    { skip: !id || !level },\n  )\n  const hasPermission = !!data?.[permission] || !!data?.ADMIN\n  return { isLoading, permission: !!hasPermission || !!AccountStore.isAdmin() }\n}\n\nconst Permission: FC<PermissionType> = ({\n  children,\n  id,\n  level,\n  permission,\n}) => {\n  const { isLoading, permission: hasPermission } = useHasPermission({\n    id,\n    level,\n    permission,\n  })\n  return (\n    <>\n      {children({\n        isLoading,\n        permission: hasPermission || AccountStore.isAdmin(),\n      }) || null}\n    </>\n  )\n}\n\nexport default Permission\n",
            'frontend/web/components/modals/base/Modal.tsx': "import {\n  Modal as _Modal,\n  ModalBody as _ModalBody,\n  ModalFooter as _ModalFooter,\n  ModalHeader as _ModalHeader,\n  ModalProps,\n} from 'reactstrap'\nimport { JSXElementConstructor, ReactNode, useCallback, useState } from 'react'\nimport { render, unmountComponentAtNode } from 'react-dom'\nimport Confirm from './ModalConfirm'\nimport ModalDefault, { interceptClose, setInterceptClose } from './ModalDefault'\nimport { getStore } from 'common/store'\nimport { Provider } from 'react-redux'\nimport { OpenConfirm } from '../../../../global'\n\nexport const ModalHeader = _ModalHeader\nexport const ModalFooter = _ModalFooter\nexport const Modal = _Modal\nexport const ModalBody = _ModalBody\n\nconst withModal = (\n  WrappedComponent: JSXElementConstructor<any>,\n  { closePointer = 'closeModal', shouldInterceptClose = false } = {},\n) => {\n  return (props: ModalProps) => {\n    // eslint-disable-next-line react-hooks/rules-of-hooks\n    const [isOpen, setIsOpen] = useState(true)\n    // eslint-disable-next-line react-hooks/rules-of-hooks\n    const toggle = useCallback(() => {\n      if (interceptClose && shouldInterceptClose) {\n        interceptClose().then((result) => {\n          if (result) {\n            setIsOpen(false)\n            setInterceptClose(null)\n          }\n        })\n      } else {\n        setIsOpen(false)\n      }\n    }, [setIsOpen])\n    // @ts-ignore\n    global[closePointer] = toggle\n\n    return (\n      <Provider store={getStore()}>\n        <WrappedComponent toggle={toggle} {...props} isOpen={isOpen} />\n      </Provider>\n    )\n  }\n}\n\nconst _Confirm = withModal(Confirm)\nconst _ModalDefault2 = withModal(ModalDefault, { closePointer: 'closeModal2' })\nconst _ModalDefault = withModal(ModalDefault, { shouldInterceptClose: true })\n\nexport const openConfirm = (global.openConfirm = ({\n  body,\n  destructive,\n  noText,\n  onNo,\n  onYes,\n  title,\n  yesText,\n}: OpenConfirm) => {\n  document.getElementById('confirm') &&\n    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion\n    unmountComponentAtNode(document.getElementById('confirm')!)\n  render(\n    <_Confirm\n      isOpen\n      isDanger={destructive}\n      onNo={onNo}\n      onYes={onYes}\n      title={title}\n      yesText={yesText}\n      noText={noText}\n    >\n      {body}\n    </_Confirm>,\n    document.getElementById('confirm'),\n  )\n})\n\nexport const openModal = (global.openModal = (\n  title: string,\n  body: ReactNode,\n  className?: string,\n  onClose?: () => void,\n) => {\n  document.getElementById('modal') &&\n    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion\n    unmountComponentAtNode(document.getElementById('modal')!)\n  render(\n    <_ModalDefault\n      isOpen\n      className={className}\n      onClosed={onClose}\n      title={title}\n    >\n      {body}\n    </_ModalDefault>,\n    document.getElementById('modal'),\n  )\n})\n\n//This is used when we show modals on top of modals, the UI pattern should be avoided if possible\nexport const openModal2 = (global.openModal2 = (\n  title: string,\n  body: ReactNode,\n  className?: string,\n  onClose?: () => void,\n) => {\n  document.getElementById('modal2') &&\n    // eslint-disable-next-line @typescript-eslint/no-non-null-assertion\n    unmountComponentAtNode(document.getElementById('modal2')!)\n  render(\n    <_ModalDefault2\n      isOpen\n      className={className}\n      onClosed={onClose}\n      title={title}\n    >\n      {body}\n    </_ModalDefault2>,\n    document.getElementById('modal2'),\n  )\n})\n",
            'frontend/web/components/pages/SegmentsPage.tsx': "import React, { FC, ReactNode, useEffect, useRef, useState } from 'react' // we need this to make JSX compile\nimport { RouterChildContext } from 'react-router'\nimport { find, sortBy } from 'lodash'\n\nimport Constants from 'common/constants'\nimport useSearchThrottle from 'common/useSearchThrottle'\nimport { Segment } from 'common/types/responses'\nimport {\n  useDeleteSegmentMutation,\n  useGetSegmentsQuery,\n} from 'common/services/useSegment'\nimport { useHasPermission } from 'common/providers/Permission'\nimport API from 'project/api'\nimport Button from 'components/base/forms/Button'\nimport ConfirmRemoveSegment from 'components/modals/ConfirmRemoveSegment'\nimport CreateSegmentModal from 'components/modals/CreateSegment'\nimport PanelSearch from 'components/PanelSearch'\nimport JSONReference from 'components/JSONReference'\nimport ConfigProvider from 'common/providers/ConfigProvider'\nimport Utils from 'common/utils/utils'\nimport ProjectStore from 'common/stores/project-store'\nimport Icon from 'components/Icon'\nimport PageTitle from 'components/PageTitle'\nimport Switch from 'components/Switch'\nimport { setModalTitle } from 'components/modals/base/ModalDefault'\nimport classNames from 'classnames'\nimport InfoMessage from 'components/InfoMessage'\n\nconst CodeHelp = require('../../components/CodeHelp')\ntype SegmentsPageType = {\n  router: RouterChildContext['router']\n  match: {\n    params: {\n      environmentId: string\n      projectId: string\n    }\n  }\n}\n\nconst SegmentsPage: FC<SegmentsPageType> = (props) => {\n  const { projectId } = props.match.params\n  const environmentId =\n    ProjectStore.getEnvironment()?.api_key || 'ENVIRONMENT_API_KEY'\n  const preselect = useRef(Utils.fromParam().id)\n  const hasNoOperators = !Utils.getFlagsmithValue('segment_operators')\n\n  const { search, searchInput, setSearchInput } = useSearchThrottle('')\n  const [page, setPage] = useState(1)\n  const [showFeatureSpecific, setShowFeatureSpecific] = useState(false)\n\n  const { data, error, isLoading, refetch } = useGetSegmentsQuery({\n    include_feature_specific: showFeatureSpecific,\n    page,\n    page_size: 100,\n    projectId,\n    q: search,\n  })\n  const [removeSegment, { isLoading: isRemoving }] = useDeleteSegmentMutation()\n\n  const segmentsLimitAlert = Utils.calculateRemainingLimitsPercentage(\n    ProjectStore.getTotalSegments(),\n    ProjectStore.getMaxSegmentsAllowed(),\n  )\n\n  useEffect(() => {\n    API.trackPage(Constants.pages.FEATURES)\n  }, [])\n  useEffect(() => {\n    if (error) {\n      // Kick user back out to projects\n      props.router.history.replace(Utils.getOrganisationHomePage())\n    }\n  }, [error, props.router.history])\n  const newSegment = () => {\n    openModal(\n      'New Segment',\n      <CreateSegmentModal\n        onComplete={(segment) => {\n          //todo: remove when CreateSegment uses hooks\n          setModalTitle(`Edit Segment: ${segment.name}`)\n          toast('Created segment')\n        }}\n        environmentId={environmentId}\n        projectId={projectId}\n      />,\n      'side-modal create-new-segment-modal',\n    )\n  }\n  const confirmRemove = (segment: Segment, cb: () => void) => {\n    openModal(\n      'Remove Segment',\n      <ConfirmRemoveSegment segment={segment} cb={cb} />,\n      'p-0',\n    )\n  }\n\n  const { permission: manageSegmentsPermission } = useHasPermission({\n    id: projectId,\n    level: 'project',\n    permission: 'MANAGE_SEGMENTS',\n  })\n\n  const editSegment = (id: number, readOnly?: boolean) => {\n    API.trackEvent(Constants.events.VIEW_SEGMENT)\n    history.replaceState({}, '', `${document.location.pathname}?id=${id}`)\n\n    openModal(\n      `Edit Segment`,\n      <CreateSegmentModal\n        segment={id}\n        onSegmentRetrieved={(segment) =>\n          setModalTitle(`Edit Segment: ${segment.name}`)\n        }\n        readOnly={readOnly}\n        onComplete={() => {\n          refetch()\n          toast('Updated Segment')\n        }}\n        environmentId={environmentId}\n        projectId={projectId}\n      />,\n      'side-modal create-segment-modal',\n      () => {\n        history.replaceState({}, '', `${document.location.pathname}`)\n      },\n    )\n  }\n  const renderWithPermission = (\n    permission: boolean,\n    name: string,\n    el: ReactNode,\n  ) => {\n    return permission ? (\n      el\n    ) : (\n      <Tooltip title={el} place='right'>\n        {Constants.projectPermissions('Manage segments')}\n      </Tooltip>\n    )\n  }\n  const segments = data?.results\n  return (\n    <div\n      data-test='segments-page'\n      id='segments-page'\n      className='app-container container'\n    >\n      <PageTitle\n        cta={\n          <>\n            {renderWithPermission(\n              manageSegmentsPermission,\n              'Manage segments',\n              <Button\n                disabled={\n                  !manageSegmentsPermission ||\n                  segmentsLimitAlert.percentage >= 100\n                }\n                id='show-create-segment-btn'\n                data-test='show-create-segment-btn'\n                onClick={newSegment}\n              >\n                Create Segment\n              </Button>,\n            )}\n          </>\n        }\n        title={'Segments'}\n      >\n        Create and manage groups of users with similar{' '}\n        <Button\n          theme='text'\n          href='https://docs.flagsmith.com/basic-features/managing-identities#identity-traits'\n          target='_blank'\n        >\n          traits\n        </Button>\n        . Segments can be used to override features within the features page for\n        any environment.{' '}\n        <Button\n          theme='text'\n          target='_blank'\n          href='https://docs.flagsmith.com/basic-features/segments'\n          className='fw-normal'\n        >\n          Learn more.\n        </Button>\n      </PageTitle>\n      <div className='segments-page'>\n        {isLoading && !segments && !searchInput && (\n          <div className='centered-container'>\n            <Loader />\n          </div>\n        )}\n        {(!isLoading || segments || searchInput) && (\n          <div>\n            {Utils.displayLimitAlert('segments', segmentsLimitAlert.percentage)}\n            <div>\n              <FormGroup className={classNames({ 'opacity-50': isRemoving })}>\n                <PanelSearch\n                  filterElement={\n                    <div className='text-right me-2'>\n                      <label className='me-2'>Include Feature-Specific</label>\n                      <Switch onChange={setShowFeatureSpecific} />\n                    </div>\n                  }\n                  renderSearchWithNoResults\n                  className='no-pad'\n                  id='segment-list'\n                  title=' '\n                  renderFooter={() => (\n                    <JSONReference\n                      className='mx-2 mt-4'\n                      title={'Segments'}\n                      json={segments}\n                    />\n                  )}\n                  items={sortBy(segments, (v) => {\n                    return `${v.feature ? 'a' : 'z'}${v.name}`\n                  })}\n                  renderRow={(\n                    { description, feature, id, name }: Segment,\n                    i: number,\n                  ) => {\n                    if (preselect.current === `${id}`) {\n                      editSegment(preselect.current, !manageSegmentsPermission)\n                      preselect.current = null\n                    }\n\n                    // TODO: remove this check\n                    // I'm leaving this here for now so that we can deploy the FE and\n                    // API independently, but we should remove this once PR #3430 is\n                    // merged and released.\n                    if (feature && !showFeatureSpecific) {\n                      return null\n                    }\n\n                    return renderWithPermission(\n                      manageSegmentsPermission,\n                      'Manage segments',\n                      <Row className='list-item clickable' key={id} space>\n                        <Flex\n                          className='table-column px-3'\n                          onClick={\n                            manageSegmentsPermission\n                              ? () => editSegment(id, !manageSegmentsPermission)\n                              : undefined\n                          }\n                        >\n                          <Row\n                            data-test={`segment-${i}-name`}\n                            className='font-weight-medium'\n                          >\n                            {name}\n                            {feature && (\n                              <div className='chip chip--xs ml-2'>\n                                Feature-Specific\n                              </div>\n                            )}\n                          </Row>\n                          <div className='list-item-subtitle mt-1'>\n                            {description || 'No description'}\n                          </div>\n                        </Flex>\n                        <div className='table-column'>\n                          <Button\n                            disabled={!manageSegmentsPermission}\n                            data-test={`remove-segment-btn-${i}`}\n                            onClick={() => {\n                              const segment = find(segments, { id })\n                              if (segment) {\n                                confirmRemove(segment, () => {\n                                  removeSegment({ id, projectId }).then(\n                                    (res) => {\n                                      toast(\n                                        <div>\n                                          Removed Segment:{' '}\n                                          <strong>{segment.name}</strong>\n                                        </div>,\n                                      )\n                                    },\n                                  )\n                                })\n                              }\n                            }}\n                            className='btn btn-with-icon'\n                          >\n                            <Icon name='trash-2' width={20} fill='#656D7B' />\n                          </Button>\n                        </div>\n                      </Row>,\n                    )\n                  }}\n                  paging={data}\n                  nextPage={() => setPage(page + 1)}\n                  prevPage={() => setPage(page - 1)}\n                  goToPage={(page: number) => setPage(page)}\n                  search={searchInput}\n                  onChange={(e: any) => {\n                    setSearchInput(Utils.safeParseEventValue(e))\n                  }}\n                  filterRow={() => true}\n                />\n              </FormGroup>\n\n              <InfoMessage>\n                Segments require you to identitfy users, setting traits will add\n                users to segments.\n              </InfoMessage>\n              <FormGroup className='mt-4'>\n                <CodeHelp\n                  title='Using segments'\n                  snippets={Constants.codeHelp.USER_TRAITS(\n                    environmentId || 'ENVIRONMENT_KEY',\n                  )}\n                />\n              </FormGroup>\n            </div>\n          </div>\n        )}\n        <FormGroup>\n          <CodeHelp\n            title='Managing user traits and segments'\n            snippets={Constants.codeHelp.USER_TRAITS(environmentId)}\n          />\n        </FormGroup>\n      </div>\n    </div>\n  )\n}\n\nmodule.exports = ConfigProvider(SegmentsPage)\n",
        }
